# Tóm tắt ưu/nhược của hai họ CTDE (paper Section 4.7)
comparison = {
    'Value Factorization (QMIX, QPLEX)': {
        'pros': [
            'Đảm bảo IGM: execution cực kỳ nhẹ (chỉ argmax local Qi)',
            'Discrete action: phù hợp với game theory, micromanagement',
            'Off-policy: sample efficient với replay buffer',
        ],
        'cons': [
            'Giới hạn bởi IGM class (không phải mọi joint Q đều factorizable)',
            'Khó scale lên continuous action space',
            'Factorization có thể sai trong bài toán interaction mạnh',
        ],
    },
    'Centralized Critic (MAPPO, COMA)': {
        'pros': [
            'Áp dụng được cho cả discrete và continuous action',
            'Convergence guarantee (local) với actor-critic theory',
            'Flexible: dùng advantage, counterfactual baseline...',
        ],
        'cons': [
            'On-policy: sample kém hiệu quả hơn',
            'Variance cao vì cần marginalize joint critic',
            'State-based critic dễ implement nhưng gây bias',
        ],
    },
}
for method, props in comparison.items():
    print(f'[{method}]')
    print('  Pros:', ' | '.join(props['pros']))
    print('  Cons:', ' | '.join(props['cons']))
    print()
